def encode_nibble(value):
	"""Port of encodeNibble from maturity.js"""
	if not isinstance(value, (int, float)):
		v = 0
	else:
		v = value
	# Clamp between 0 and 5, multiply by 2 for 0.5 precision, round, clamp 0 to 10
	clamped_v = max(0, min(5, v))
	rounded = round(clamped_v * 2)
	return min(10, max(0, rounded))

def pack_mat_mask(sex, violence, language, drugs):
	"""Port of packMatMask from maturity.js"""
	return (
		(encode_nibble(sex)      << 0)  |
		(encode_nibble(violence) << 4)  |
		(encode_nibble(language) << 8)  |
		(encode_nibble(drugs)    << 12)
	)


def update_movies_json(movies_json_path, cache_data, meta_data=None):
	# 1. Load movies database
	with open(movies_json_path, 'r', encoding='utf-8') as f:
		data = json.load(f)
		
	# 2. Iterate through and update each movie entry matching its ID
	processed_count = 0
	total_movies = len(data.get("movies", []))

	print(f"Starting long-running predictions for {total_movies} movies...")

	for movie in data.get("movies", []):
		imdb_id = movie.get("id")  # e.g., "tt0111161"
		
		# Check if cache entry exists for this movie to run prediction
		if imdb_id in cache_data:
			#if 'mat' in cache_data[imdb_id]:
			#	continue
			try:
				# Generate predictions using your fixed predict_movie function
				preds = predict_movie(imdb_id, cache_data[imdb_id], meta_data)
				
				# Compute the 16-bit packed integer mask
				mask = pack_mat_mask(
					sex=preds.get("csm_sex", 0),
					violence=preds.get("csm_violence", 0),
					language=preds.get("csm_language", 0),
					drugs=preds.get("csm_drugs", 0)
				)
				
				# Append/Update the mask attribute in the JSON object
				movie["mat"] = mask
				cache_data[imdb_id]['mat'] = mask                
				processed_count += 1
				
			except Exception as e:
				print(f"Skipping {imdb_id} due to prediction error: {e}")
		
		# Periodic save every 250 iterations
		if processed_count > 0 and processed_count % 250 == 0:
			print(f"--> Saving progress checkpoint at {processed_count} movies...")
			with open(movies_json_path, 'w', encoding='utf-8') as f:
				json.dump(data, f, separators=(',', ':'), ensure_ascii=False)
			with open(args.cache, 'w', encoding='utf-8') as f:
				json.dump(cache_data, f, separators=(',', ':'), ensure_ascii=False)
			if processed_count > 5000:
				return
				
	# Final write to catch any remaining changes
	print(f"\nFinished processing all movies! Finalizing file save...")
	with open(movies_json_path, 'w', encoding='utf-8') as f:
		json.dump(data, f, separators=(',', ':'), ensure_ascii=False)
	with open(args.cache, 'w', encoding='utf-8') as f:
		json.dump(cache_data, f, separators=(',', ':'), ensure_ascii=False)
	print(f"Done. Successfully processed and stored masks for {processed_count} entries.")

def _imdb_feats(raw_guide):
	feats = {}
	guide_map = {}
	for e in (raw_guide or []):
		if isinstance(e, dict) and "category" in e:
			guide_map[e["category"]] = e
			
	import math
	for cat in IMDB_CATS:
		cat_l = cat.lower()
		entry = guide_map.get(cat, {})
		bk = {}
		if isinstance(entry, dict):
			for b in entry.get("severityBreakdowns", []):
				if isinstance(b, dict) and "severityLevel" in b:
					bk[str(b["severityLevel"]).lower()] = b.get("voteCount") or 0
					
		total = weighted = 0
		for i, lv in enumerate(SEVERITY_ORDER):
			try: v = int(bk.get(lv, 0))
			except: v = 0
			feats[f"imdb_{cat_l}_{lv}"] = v
			total += v; weighted += v * i
			
		feats[f"imdb_{cat_l}_total"] = total
		mu = (weighted / total) if total > 0 else 0.0
		feats[f"imdb_{cat_l}_weighted"] = mu
		
		p_severe   = (bk.get("severe", 0) / total) if total > 0 else 0.0
		p_moderate = (bk.get("moderate", 0) / total) if total > 0 else 0.0
		p_mild     = (bk.get("mild", 0) / total) if total > 0 else 0.0
		p_none     = (bk.get("none", 0) / total) if total > 0 else 0.0
		
		feats[f"imdb_{cat_l}_severe_ratio"]   = p_severe
		feats[f"imdb_{cat_l}_moderate_ratio"] = p_moderate
		feats[f"imdb_{cat_l}_mild_ratio"]     = p_mild
		feats[f"imdb_{cat_l}_none_ratio"]     = p_none
		feats[f"imdb_{cat_l}_mature_ratio"]   = p_severe + p_moderate
		
		entropy = variance = 0.0
		for i, p in enumerate([p_none, p_mild, p_moderate, p_severe]):
			if p > 0:
				entropy -= p * math.log2(p)
				variance += p * ((i - mu) ** 2)
		feats[f"imdb_{cat_l}_entropy"] = entropy
		feats[f"imdb_{cat_l}_variance"] = variance
		feats[f"imdb_{cat_l}_std_dev"]  = variance ** 0.5
		
		v_severe   = bk.get("severe", 0)
		v_moderate = bk.get("moderate", 0)
		v_mild     = bk.get("mild", 0)
		feats[f"imdb_{cat_l}_severe_acceleration"] = (v_severe / (v_moderate + 1))
		feats[f"imdb_{cat_l}_moderate_acceleration"] = (v_moderate / (v_mild + 1))
		feats[f"imdb_{cat_l}_sample_gravity"] = mu * math.log1p(total)

	v_total = feats.get("imdb_violence_total", 0)
	p_total = feats.get("imdb_profanity_total", 0)
	s_total = feats.get("imdb_sexual_content_total", 0)
	feats["imdb_contrast_violence_vs_profanity"] = (v_total / p_total) if p_total > 0 else 0.0
	feats["imdb_contrast_sex_vs_violence"] = (s_total / v_total) if v_total > 0 else 0.0
	return feats

def build_row(imdb_id, c, meta=None):
	meta = meta or {}
	row = {}
	row["year"]       = meta.get("year")       or c.get("year")
	row["rating"]     = meta.get("rating")     or c.get("imdbRating")
	row["votes"]      = meta.get("votes")      or c.get("votes")
	row["is_season"]  = int(bool(meta.get("isSeason", False)))
	row["popularity"] = c.get("popularity") or 0
	genres = meta.get("genres") or c.get("genres") or 0
	
	try: genres = int(genres)
	except: genres = 0
	for n, b in GENRE_BITS.items():
		row[f"genre_{n.lower().replace('-','_')}"] = int(bool(genres & (1 << b)))
		
	raw_year = row["year"]
	year_val = raw_year if pd.notna(raw_year) else 2000

	year = np.clip(year_val - 2000, 0, 30)  # score drift over the years
	
	mpa = c.get("mpaCertification")
	row["mpa_ordinal"] = MPA_ORDINAL.get(mpa) if mpa else None
	for label in ["G", "PG", "PG-13", "R", "NC-17"]:
		row[f"mpa_{label.replace('-','_')}"] = int(mpa == label) if mpa else 0
	row["has_mpa"] = int(mpa is not None)
	row.update(_imdb_feats(c.get("rawParentsGuide")))
	row["has_imdb_guide"] = int(bool(c.get("rawParentsGuide")))
	
	
	
	for feat in FEATURES.get(TARGETS[0], []):
		if feat.startswith("tfidf_") and feat not in row:
			row[feat] = 0.0
	return row

_models = {}
def _model(t):
	if t not in _models:
		_models[t] = lgb.Booster(model_file=os.path.join(MODEL_DIR, f"model_{t}.lgb"))
	return _models[t]

def _load_pred_modes():
    """Read pred_mode per target from meta.json written by train.py."""
    meta_path = os.path.join(MODEL_DIR, "meta.json")
    modes = {}
    try:
        with open(meta_path) as f:
            for entry in json.load(f):
                if entry and "target" in entry:
                    modes[entry["target"]] = entry.get("pred_mode", "argmax")
    except Exception:
        pass
    return modes

_PRED_MODES = None  # loaded lazily

def predict_movie(imdb_id, cache_entry, meta=None):
    global _PRED_MODES
    if _PRED_MODES is None:
        _PRED_MODES = _load_pred_modes()

    row = build_row(imdb_id, cache_entry, meta)
    out = {}

    for t in TARGETS:
        X = np.array([[row.get(f, np.nan) if row.get(f) is not None else np.nan
                       for f in FEATURES[t]]])

        # Shape: (1, n_classes) — class probabilities
        probs = _model(t).predict(X)[0]  # e.g. [0.05, 0.10, 0.52, 0.25, 0.06, 0.02]

        mode = _PRED_MODES.get(t, "argmax")
        if mode == "ev":
            # Expected value: weighted average of class indices, rounded to nearest int
            n_classes = len(probs)
            ev = float(np.dot(np.arange(n_classes), probs))
            out[t] = int(round(ev))
        else:
            # argmax: most probable class (default, matches clf_argmax training variant)
            out[t] = int(np.argmax(probs))

    return out

